import requests, itertools
base='http://localhost:5000'
# common static directories seen
bases=['/static/','/static/img/','/static/assets/','/static/css/','/static/js/','/static/flags/','/static/flag/','/static/files/','/static/uploads/']
# candidate names and extensions
names=['flag','FLAG','flag22','flag_22','flag-star','star_flag','dalgona_flag','xss22_flag','xss-22','success','win','victory','answer','key']
exts=['.txt','.png','.jpg','.jpeg','.gif','.svg','.ico','']

cands=set()
for b in bases:
    for n in names:
        for e in exts:
            cands.add(b+n+e)
            for sep in ['-','_','']:
                for s in ['1','2','22','020','2022','2024']:
                    cands.add(b+n+sep+s+e)

hits=[]
for p in sorted(cands):
    try:
        r=requests.get(base+p, timeout=2)
        if r.status_code==200:
            print('HIT',p,'CT=',r.headers.get('Content-Type'),'len',len(r.content))
            hits.append(p)
    except Exception:
        pass

print('Total hits:',len(hits))

